function check_permissions()
    local token = ngx.var.http_authorization
    if not token then
        ngx.status = 401
        ngx.say("Unauthorized")
        ngx.exit(ngx.HTTP_UNAUTHORIZED)
    end

    -- Validate the authentication token (simplified example)
    if token ~= "valid_token" then
        ngx.status = 403
        ngx.say("Forbidden")
        ngx.exit(ngx.HTTP_FORBIDDEN)
    end

    local user_role = get_user_role(token)  -- Function to retrieve user role from token

    -- Skip permission checks for certain endpoints
    if ngx.var.uri:find("/admin") or ngx.var.uri:find("/api") then
        return
    end

    -- Define allowed roles for the endpoint
    local allowed_roles = {"user", "guest"}

    -- Check if user role is in allowed roles
    local has_permission = false
    for _, role in ipairs(allowed_roles) do
        if user_role == role then
            has_permission = true
            break
        end
    end

    if not has_permission then
        ngx.status = 403
        ngx.say("Forbidden")
        ngx.exit(ngx.HTTP_FORBIDDEN)
    end
end

